// Normaliza o payload da Evolution API
// Eventos relevantes: 'messages.upsert'
// Ignora grupos, ignora mensagens sem texto, extrai campos principais

const body = items[0].json.body || items[0].json;
const event = body.event;

// So processamos messages.upsert
if (event !== 'messages.upsert') {
  return [{ json: { skip: true, reason: 'evento_nao_relevante', event } }];
}

const data = body.data || {};
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const fromMe = !!key.fromMe;
const msgId = key.id;

// Ignora grupos (terminam em @g.us)
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { skip: true, reason: 'mensagem_de_grupo' } }];
}

// Numero limpo (tira @s.whatsapp.net)
const number = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
if (!number) {
  return [{ json: { skip: true, reason: 'sem_numero' } }];
}

// Extrai texto da mensagem (cobrindo varios formatos)
const msg = data.message || {};
let content =
  msg.conversation ||
  (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
  (msg.imageMessage && msg.imageMessage.caption) ||
  (msg.videoMessage && msg.videoMessage.caption) ||
  (msg.documentMessage && msg.documentMessage.caption) ||
  '';

// Marca tipo de midia pra dar contexto quando nao houver texto
if (!content) {
  if (msg.imageMessage) content = '[IMAGEM enviada pelo mentorado]';
  else if (msg.videoMessage) content = '[VIDEO enviado pelo mentorado]';
  else if (msg.audioMessage) content = '[AUDIO enviado pelo mentorado]';
  else if (msg.documentMessage) content = '[DOCUMENTO enviado pelo mentorado]';
  else if (msg.stickerMessage) content = '[FIGURINHA enviada pelo mentorado]';
  else return [{ json: { skip: true, reason: 'mensagem_sem_conteudo' } }];
}

const pushName = data.pushName || null;

return [{
  json: {
    skip: false,
    direction: fromMe ? 'outgoing' : 'incoming',
    whatsapp_number: number,
    contact_name: pushName,
    content,
    evolution_msg_id: msgId,
    raw_event: event
  }
}];

// Monta a mensagem do relatorio diario pro Slack
const d = items[0].json;

const hoje = new Date().toLocaleDateString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  day: '2-digit', month: '2-digit', year: 'numeric',
  weekday: 'long'
});

// Helpers
function fmtMin(valor) {
  if (valor === null || valor === undefined) return '-';
  const n = Number(valor);
  if (isNaN(n)) return '-';
  if (n < 60) return n.toFixed(1) + ' min';
  const h = Math.floor(n / 60);
  const m = Math.round(n % 60);
  return h + 'h ' + m + 'min';
}

const total       = Number(d.total_mensagens || 0);
const mentorados  = Number(d.mentorados_unicos || 0);
const respondidas = Number(d.mensagens_respondidas || 0);
const pendentes   = Number(d.mensagens_pendentes || 0);
const nomes       = d.nomes_unicos || '-';

const pctResp = total > 0 ? Math.round((respondidas / total) * 100) : 0;

// Indicador visual do tempo medio
let indicador = '\ud83d\udfe2'; // verde
const medio = Number(d.tempo_medio_min || 0);
if (medio > 120) indicador = '\ud83d\udd34';        // > 2h
else if (medio > 30) indicador = '\ud83d\udfe1';    // > 30min

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: '\ud83d\udcc5 Relatorio diario - ' + hoje, emoji: true }
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: '\ud83d\udce8 *Mensagens recebidas*\n' + total },
      { type: 'mrkdwn', text: '\ud83d\udc65 *Mentorados unicos*\n' + mentorados }
    ]
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: '\u2705 *Respondidas*\n' + respondidas + ' (' + pctResp + '%)' },
      { type: 'mrkdwn', text: '\u23f3 *Ainda pendentes*\n' + pendentes }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: indicador + ' *Tempo de resposta do CS hoje*' }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: '*Medio*\n' + fmtMin(d.tempo_medio_min) },
      { type: 'mrkdwn', text: '*Mediana*\n' + fmtMin(d.tempo_mediano_min) },
      { type: 'mrkdwn', text: '*Mais rapido*\n' + fmtMin(d.tempo_min_min) },
      { type: 'mrkdwn', text: '*Mais demorado*\n' + fmtMin(d.tempo_max_min) }
    ]
  },
  { type: 'divider' },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: '\ud83d\udc64 *Mentorados que chamaram hoje:* ' + nomes }]
  }
];

return [{
  json: {
    blocks,
    fallback_text: 'Relatorio diario - ' + total + ' mensagens de ' + mentorados + ' mentorados'
  }
}];

// Pareia a resposta do GPT com os dados originais do contato
const claudeResp = $json;
const original   = $('Montar Request Claude').item.json;

let parsed;
try {
  parsed = JSON.parse(claudeResp.content[0].text);
} catch (e) {
  parsed = {
    urgencia: 'MEDIA',
    intencao: 'ERRO_PARSE',
    justificativa: 'Falha no parse do GPT - revisar manualmente',
    sugestao_resposta: '(Erro ao gerar sugestao - revise a mensagem original)'
  };
}

const urgenciaNorm = (parsed.urgencia || 'MEDIA').toUpperCase();
const intencaoNorm = (parsed.intencao || 'NAO_MAPEADA').toUpperCase();

return {
  json: {
    whatsapp_number: original.whatsapp_number,
    contact_name: original.contact_name || 'Sem nome',
    qtd_mensagens: Number(original.qtd_mensagens),
    horas_aguardando: original.horas_aguardando,
    mensagens: original.mensagens_concatenadas,
    urgencia: urgenciaNorm,
    intencao: intencaoNorm,
    justificativa: parsed.justificativa || '',
    sugestao_resposta: parsed.sugestao_resposta || ''
  }
};

const urgencia = $json.urgencia || 'BAIXA';
const intencao = $json.intencao || 'NAO_MAPEADA';
const justificativa = $json.justificativa || '';
const sugestao = $json.sugestao_resposta || '';
const nome = $json.contact_name || 'Sem nome';
const horas = $json.horas_aguardando || '0';
const qtd = $json.qtd_mensagens || '0';
const msgs = $json.mensagens || '';

const emoji = { 'ALTA': '🔴', 'MEDIA': '🟡', 'BAIXA': '🟢' }[urgencia] || '⚪';

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${emoji} ${nome} — ${urgencia}` }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Situação:*\n${intencao}` },
      { type: 'mrkdwn', text: `*Aguardando:*\n${horas}h (${qtd} mensagem(ns))` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Por que essa urgência:*\n${justificativa}`
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Mensagens recebidas:*\n\`\`\`${msgs.slice(0, 500)}${msgs.length > 500 ? '...' : ''}\`\`\``
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Sugestão de resposta:*\n${sugestao}`
    }
  },
  { type: 'divider' }
];

return {
  json: {
    blocks: JSON.stringify(blocks),
    text: `${emoji} ${nome}: ${urgencia}`
  }
};

const items = $('Parse + Merge').all();
const results = [];

for (const item of items) {
  const urgencia = item.json.urgencia || 'BAIXA';
  const intencao = item.json.intencao || 'NAO_MAPEADA';
  const nome = item.json.contact_name || 'Sem nome';
  const horas = item.json.horas_aguardando || '0';
  const qtd = item.json.qtd_mensagens || '0';
  const msgs = item.json.mensagens || '';
  const sugestao = item.json.sugestao_resposta || '';
  const justificativa = item.json.justificativa || '';

  const emoji = { 'ALTA': '🔴', 'MEDIA': '🟡', 'BAIXA': '🟢' }[urgencia] || '⚪';

  let texto = `${emoji} *${nome}* — ${urgencia}\n\n`;
  texto += `*Situação identificada:* ${intencao}\n`;
  texto += `*Aguardando:* ${horas}h (${qtd} mensagem(ns))\n`;
  texto += `*Por que essa urgência:* ${justificativa}\n\n`;
  texto += `*Mensagens recebidas:*\n\`\`\`${msgs.slice(0, 500)}${msgs.length > 500 ? '...' : ''}\`\`\`\n\n`;
  texto += `*Sugestão de resposta:*\n${sugestao}`;

  results.push({ json: { text: texto } });
}

return results;
